insert into wac_drama_script values (112102, 112, 21, 'vo_wac_220215', 'vo_wac_220215_018', '0', '0', '', '', '', '');
insert into wac_drama_script values (112103, 112, 11, '106011', '気持ち悪そうなもの描こうとすんな！\\nま、計画自体はいいんじゃない？\\n楽しそうだし……それじゃ、\\nいっちょやってやろうじゃないの！', '10', '1', '1', '0', '0', '0.5');
