insert into wac_drama_script values (1012009, 1012, 11, '100711', 'プリンなの、ここにもプリンなの、\\nあっちにもそっちにもプリンなの\\nなんて、ウソなの。\\nちゃんと習った通りに描くの。', '10', '1', '1', '0', '0', '0.5');
