insert into wac_drama_script values (1012012, 1012, 11, '100711', '……う～、でもプリンのことを\\n考えてたらおなかが空いてきたの。\\nだからプリン描いて壁を食べてみたの。\\n全然美味しくないの！', '10', '1', '1', '0', '0', '0.5');
