insert into wac_drama_script values (4012009, 4012, 11, '106611', 'このっ、このやろっ！\\nここをこうしてフィニ～ッシュ！\\nふぅ。ボスへの怒り……じゃなくて\\n街への想いを込めた傑作ができたです。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (4012010, 4012, 91, '0', '', '', '', '', '', '', '');
