insert into wac_drama_script values (8512027, 8512, 11, '102111', 'そんなことないよ、アヤネちゃん……！\\nすっごく元気が出てくるような絵で\\n私は、大好きだよ……♪', '10', '1', '1', '0', '0', '0.5');
