insert into wac_drama_script values (8512032, 8512, 11, '102811', 'そうね。\\nのびのびとした描き方で、\\n見ていて気持ちいいわ。\\nとってもアヤネらしいわね。', '10', '1', '1', '0', '0', '0.5');
