insert into wac_drama_script values (8612022, 8612, 11, '105911', 'ふふ、こうしてみなさまと一緒に\\n絵を描くというのもまた\\n楽しいものでございますね。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (8612023, 8612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (8612024, 8612, 3, '105911', 'wac_idle_wish', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (8612025, 8612, 3, '106411', 'wac_talk_smile_in', '0', 'wac_talk_smile_loop', '1', '0.2', '', '');
insert into wac_drama_script values (8612026, 8612, 21, 'vo_wac_220511', 'vo_wac_220511_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (8612027, 8612, 11, '106411', 'そうね。慣れないせいもあって\\n緊張しちゃうけど、\\nコッコロさんやみんなが一緒だと\\n落ち着いて、楽しくやれる気がするわ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (8612028, 8612, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (8612029, 8612, 3, '106411', 'wac_idle_smile', '1', '', '1', '0.2', '', '');
