insert into wac_drama_script values (8612042, 8612, 11, '105911', '……本当に、みなさまと【美食殿】の\\n仲間でいられて幸せです。\\nさて、ひと仕事終えたあとは\\nおいしいごはんにいたしましょう。', '10', '1', '1', '0', '0', '0.5');
