insert into wac_drama_script values (14112023, 14112, 3, '101311', 'wac_talk_wish_in', '0', 'wac_talk_wish_loop', '1', '0.2', '', '');
insert into wac_drama_script values (14112024, 14112, 21, 'vo_wac_220705', 'vo_wac_220705_000', '0', '0', '', '', '', '');
insert into wac_drama_script values (14112025, 14112, 11, '101311', 'やった！\u3000これにて完成でござるよ～！\\nう～ん、色使いといい、タッチといい、\\n今度も素晴らしい出来栄えですな～！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14112026, 14112, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14112027, 14112, 3, '101311', 'wac_idle_wish', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (14112028, 14112, 3, '105611', 'wac_talk_smile_in_L', '0', 'wac_talk_smile_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (14112029, 14112, 21, 'vo_wac_220705', 'vo_wac_220705_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (14112030, 14112, 11, '105611', '上出来、上出来。\\nさて、絵も完成したことだし、\\nみんなでパパっと片づけをして\\n食事にでも行くとするかい。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14112031, 14112, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14112032, 14112, 3, '105611', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (14112033, 14112, 3, '105111', 'wac_talk_doya_in', '0', 'wac_talk_doya_loop', '1', '0.2', '', '');
insert into wac_drama_script values (14112034, 14112, 21, 'vo_wac_220705', 'vo_wac_220705_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (14112035, 14112, 11, '105111', 'あら？\u3000でも……\\n片づけはもう済んでるみたいよ？\\nうふふ、いったいどこの「いい子」が\\nやってくれたのかしらね～？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14112036, 14112, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14112037, 14112, 3, '105111', 'wac_idle_doya', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (14112038, 14112, 3, '102711', 'wac_talk_smile_in_L', '0', 'wac_talk_smile_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (14112039, 14112, 21, 'vo_wac_220705', 'vo_wac_220705_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (14112040, 14112, 11, '102711', 'クスクス……私は見ていましたよ。\\nアンナさん、あなたがいそいそと\\n後ろで道具を片づけているのを……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14112041, 14112, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14112042, 14112, 3, '102711', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (14112043, 14112, 3, '105611', 'wac_talk_doya_in_L', '0', 'wac_talk_doya_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (14112044, 14112, 21, 'vo_wac_220705', 'vo_wac_220705_004', '0', '0', '', '', '', '');
insert into wac_drama_script values (14112045, 14112, 11, '105611', 'はは、そりゃ助かった。\\nお前さん、物言いは突飛だが、\\nそういうところにはよく気が回るねえ。\\nいい子じゃないか。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14112046, 14112, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14112047, 14112, 3, '105611', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (14112048, 14112, 3, '100911', 'wac_talk_anger', '1', '', '', '0.2', '', '');
insert into wac_drama_script values (14112049, 14112, 21, 'vo_wac_220705', 'vo_wac_220705_005', '0', '0', '', '', '', '');
insert into wac_drama_script values (14112050, 14112, 11, '100911', 'なっ、いい子とか言うなぁ！\\nて、手がすいたからやっただけで、\\nそこはせめて全知全能と……\\nうぅ、生暖かい目で見るなぁっ！', '10', '1', '1', '0', '0', '0.5');
