insert into wac_drama_script values (14312022, 14312, 11, '101711', 'ふふ、絵を描くのって楽しいさ～！\\n描いても描いても飽きないし……\\n歌って踊ればもっと楽しくなるさ～！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14312023, 14312, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14312024, 14312, 3, '101711', 'wac_idle_kyapi', '1', '', '1', '0.2', '', '');
