insert into wac_drama_script values (14312031, 14312, 21, 'vo_wac_220707', 'vo_wac_220707_002', '0', '0', '', '', '', '');
insert into wac_drama_script values (14312032, 14312, 11, '101011', 'うちもこの間、それやってしもうたなぁ。\\nふふ、でも安心しておくれやす。\\nきれいに落とす方法、\\nうちが教えてあげますえ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14312033, 14312, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14312034, 14312, 3, '101011', 'wac_idle_smile_L', '1', '', '1', '0.2', '', '');
