insert into wac_drama_script values (14312037, 14312, 11, '101411', 'ふふ、帰ったらみんなで\\nお風呂に入らないといけないね。\\n……私も少し服を汚してしまった。\\n自分がキャンバスになった気分だよ。', '10', '1', '1', '0', '0', '0.5');
