insert into wac_drama_script values (14712026, 14712, 11, '100911', 'シグルドー！\u3000見てくれ見てくれ！\\n今回の絵は、歴史に残る最高傑作……！\\n貴様には、その目撃者になる\\n栄誉を授けよう！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14712027, 14712, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (14712028, 14712, 3, '100911', 'wac_idle_kyapi_L', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (14712029, 14712, 3, '101311', 'wac_talk_kyapi_in_L', '0', 'wac_talk_kyapi_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (14712030, 14712, 21, 'vo_wac_220711', 'vo_wac_220711_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (14712031, 14712, 11, '101311', 'さすがだね、アンナたそ！\\nけど私も負けないよ～！\\n芸術の神が舞い降りたかのような\\nこの完成度、ぜひご照覧あれ～！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (14712032, 14712, 91, '0', '', '', '', '', '', '', '');
