insert into wac_drama_script values (16112028, 16112, 11, '104911', 'リノちゃん、こーら☆\\nそんな言い方失礼だよ？\\nマスターはいつも忙しくて\\n大変なんだから。', '10', '1', '1', '0', '0', '0.5');
