insert into wac_drama_script values (16412025, 16412, 11, '105311', 'よし、今度も素晴らしい完成度だ！\\n役割分担をしたら、飛躍的に\\n描くのが早くなったな！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16412026, 16412, 91, '0', '', '', '', '', '', '', '');
