insert into wac_drama_script values (16412029, 16412, 21, 'vo_wac_220728', 'vo_wac_220728_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (16412030, 16412, 11, '103011', 'シュバッ！\u3000シュバババッ！\\n色塗りはワタシにお任せデース！\\nこの絵筆二刀流で、瞬く間に\\nカラフルにしてみせマース！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (16412031, 16412, 91, '0', '', '', '', '', '', '', '');
