insert into wac_drama_script values (16412050, 16412, 11, '105311', 'うむ！\u3000完璧なコンビネーションだ！\\n過去一番の団結と言っても過言ではないな！\\n……それはそれでちょっと複雑だが。\\nこの調子でお絵描き事業を完遂するぞ！', '10', '1', '1', '0', '0', '0.5');
