insert into wac_drama_script values (17412028, 17412, 11, '110911', 'こっかよさん！\\nちょ、それ早く言ってくださいよ！\\nそういうことなら話変わってきますよ？\\nよーし、俄然ちぇるって来ましたね！', '10', '1', '1', '0', '0', '0.5');
