insert into wac_drama_script values (17612032, 17612, 11, '101011', '一応、これってギルドの\\nお仕事なんやけどなぁ……\\nまぁ、なんでも楽しゅうできるのが、\\n一番ええことやからねぇ♪', '10', '1', '1', '0', '0', '0.5');
