insert into wac_drama_script values (18812029, 18812, 3, '100911', 'wac_talk_doya_in_surprise_L', '0', 'wac_talk_doya_loop_surprise_L', '1', '0.2', '', '');
insert into wac_drama_script values (18812030, 18812, 21, 'vo_wac_220821', 'vo_wac_220821_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (18812031, 18812, 11, '100911', 'むっ、ちょっと待て。\\nこの絵のテーマは、繰り返される\\n運命の闘争が織りなす限りなき\\nウロボロスの循環ではないのか！？', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (18812032, 18812, 91, '0', '', '', '', '', '', '', '');
