insert into wac_drama_script values (18812036, 18812, 11, '102711', 'クスクス……違います。\\nこれはあのおかたへの愛……\\n枯れることのない、永遠の愛が\\nテーマですわ……', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (18812037, 18812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (18812038, 18812, 3, '102711', 'wac_idle_wish_L', '1', '', '1', '0.2', '', '');
