insert into wac_drama_script values (19812029, 19812, 11, '103011', 'シュバババババ～♪\\n忍法に不可能はありまセン！\\nウキヨエを壁に描くのも\\nお手の物デス！', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (19812030, 19812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (19812031, 19812, 3, '103011', 'wac_idle_doya', '1', '', '1', '0.2', '', '');
insert into wac_drama_script values (19812032, 19812, 3, '105311', 'wac_talk_sad_in_L', '0', 'wac_talk_sad_loop_L', '1', '0.2', '', '');
insert into wac_drama_script values (19812033, 19812, 21, 'vo_wac_220831', 'vo_wac_220831_001', '0', '0', '', '', '', '');
insert into wac_drama_script values (19812034, 19812, 11, '105311', 'いや、浮世絵って\\nこんな感じだったか？\\nオーエドで見たのは、もう少し\\n違う雰囲気だった気がするのだが。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (19812035, 19812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (19812036, 19812, 3, '105311', 'wac_idle_sad_L', '1', '', '1', '0.2', '', '');
