insert into wac_drama_script values (19812043, 19812, 21, 'vo_wac_220831', 'vo_wac_220831_003', '0', '0', '', '', '', '');
insert into wac_drama_script values (19812044, 19812, 11, '104511', 'そ、そうですね……\\nドＳさんも多種多様な攻めを\\n繰り出してきますけど、全部\\nクウカにとっては快感ですし。', '10', '1', '1', '0', '0', '0.5');
insert into wac_drama_script values (19812045, 19812, 91, '0', '', '', '', '', '', '', '');
insert into wac_drama_script values (19812046, 19812, 3, '104511', 'wac_idle_wish', '1', '', '1', '0.2', '', '');
