insert into wac_drama_script values (19812048, 19812, 21, 'vo_wac_220831', 'vo_wac_220831_004', '0', '0', '', '', '', '');
insert into wac_drama_script values (19812049, 19812, 11, '105511', 'それは流石に違う気がします……\\nでも、みんなで描いた絵が、\\n浮世絵みたいにきれいに\\nできたのはそのとおりですね♪', '10', '1', '1', '0', '0', '0.5');
